import LlamaCloud from '@llamaindex/llama-cloud';
import fs from 'fs';
import path from 'path';

async function main() {
  const projectDir = '/home/user/myproject';
  const pdfPath = path.join(projectDir, 'sample.pdf');
  const trialIdPath = '/logs/artifacts/trial_id';
  const outputMdPath = path.join(projectDir, 'output.md');
  const outputLogPath = path.join(projectDir, 'output.log');

  try {
    // Read trial_id
    const trialId = fs.readFileSync(trialIdPath, 'utf-8').trim();

    // Initialize LlamaCloud client
    // It automatically reads LLAMA_CLOUD_API_KEY from the environment
    const client = new LlamaCloud();

    console.log('Uploading file...');
    // Upload the PDF
    const file = await client.files.create({
      file: fs.createReadStream(pdfPath),
      purpose: 'parse',
    });

    const fileId = file.id;
    console.log(`File uploaded with ID: ${fileId}`);

    console.log('Parsing file...');
    // Run the parse job
    const result = await client.parsing.parse({
      file_id: fileId,
      tier: 'agentic',
      version: 'latest',
      expand: ['markdown'],
    });

    if (!result.markdown || !result.markdown.pages) {
      throw new Error('No markdown pages returned from LlamaParse');
    }

    const pages = result.markdown.pages;
    const pagesCount = pages.length;

    // Concatenate markdown of every page
    const fullMarkdown = pages.map((page: any) => page.markdown).join('\n\n---\n\n');

    // Write output.md
    fs.writeFileSync(outputMdPath, fullMarkdown);
    console.log(`Markdown written to ${outputMdPath}`);

    // Write output.log
    const logContent = `trial_id: ${trialId}\npages_parsed: ${pagesCount}\n`;
    fs.writeFileSync(outputLogPath, logContent);
    console.log(`Log written to ${outputLogPath}`);

  } catch (error) {
    console.error('Error during parsing:', error);
    process.exit(1);
  }
}

main();

